mapattrs'.body:
lib.mapAttrs' (name: value: lib.nameValuePair ("foo_" + name) ("bar-" + value)) {
  x = "a";
  y = "b";
};

meta.body:
meta = {
  description = "$1";
  homepage = "$2";
  license = lib.licenses.$3;
  maintainers = with lib.maintainers; [ $0 ];
};

mkd.body:
stdenv.mkDerivation (finalAttrs: {
  pname = "$1";
  version = "$2";

  src = $3

  nativeBuildInputs = [
    $4
  ];
  buildInputs = [
    $0
  ];
})

submodule.body:
submodule {
  options = {
    enable$0 = mkOption {
      type = bool;
      default = true;
    };
  };
}
